class Solution:
    def canSeePersonsCount(self, heights):
        n = len(heights)
        ans = [0] * n
        for i in range(n):
            mx = -1
            for j in range(i + 1, n):
                if heights[j] > mx:
                    ans[i] += 1
                    mx = heights[j]
                    if heights[j] > heights[i]:
                        break
        return ans

