var canSeePersonsCount = function(heights) {
    const n = heights.length;
    const ans = new Array(n).fill(0);
    const stack = [];
    for (let i = n - 1; i >= 0; i--) {
        while (stack.length && stack[stack.length - 1] < heights[i]) {
            stack.pop();
            ans[i]++;
        }
        if (stack.length) ans[i]++;
        stack.push(heights[i]);
    }
    return ans;
};
